CREATE TABLE IF NOT EXISTS empresa_logo_documental_version (
    id BIGSERIAL PRIMARY KEY,
    version INTEGER NOT NULL UNIQUE,
    estado VARCHAR(20) NOT NULL,
    nombre_archivo_original VARCHAR(255) NOT NULL,
    content_type VARCHAR(80) NOT NULL,
    tamano_bytes BIGINT NOT NULL,
    ancho_px INTEGER NOT NULL,
    alto_px INTEGER NOT NULL,
    sha256 VARCHAR(64) NOT NULL,
    contenido BYTEA NOT NULL,
    vigente_desde TIMESTAMP NOT NULL,
    vigente_hasta TIMESTAMP NULL,
    creado_en TIMESTAMP NOT NULL,
    creado_por VARCHAR(120) NULL,
    motivo_cambio TEXT NULL,
    CONSTRAINT chk_empresa_logo_documental_estado
        CHECK (estado IN ('VIGENTE', 'RETIRADA'))
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_empresa_logo_documental_vigente
    ON empresa_logo_documental_version (estado)
    WHERE estado = 'VIGENTE';

INSERT INTO empresa_logo_documental_version (
    version,
    estado,
    nombre_archivo_original,
    content_type,
    tamano_bytes,
    ancho_px,
    alto_px,
    sha256,
    contenido,
    vigente_desde,
