)
ON CONFLICT (version) DO NOTHING;

ALTER TABLE orden_compra
    ADD COLUMN IF NOT EXISTS empresa_logo_documental_version_id BIGINT NULL;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'fk_orden_compra_empresa_logo_documental_version'
    ) THEN
        ALTER TABLE orden_compra
            ADD CONSTRAINT fk_orden_compra_empresa_logo_documental_version
            FOREIGN KEY (empresa_logo_documental_version_id)
            REFERENCES empresa_logo_documental_version (id);
    END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_orden_compra_empresa_logo_documental_version
    ON orden_compra (empresa_logo_documental_version_id);

UPDATE orden_compra oc
SET empresa_logo_documental_version_id = eld.id
FROM empresa_logo_documental_version eld
WHERE eld.version = 1
  AND oc.empresa_logo_documental_version_id IS NULL
  AND (
      oc.estado IN (2, 3)
      OR oc.fecha_envio_proveedor IS NOT NULL
  );
